# ===========================================================================
# 1. Happy-path: valid Observation creation
# ===========================================================================

class TestValidObservationCreation:

    def test_create_minimal_observation_returns_observation(
        self, service, minimal_observation
    ):
        result = service.create(minimal_observation)
        assert isinstance(result, Observation)

    def test_create_assigns_observation_id(self, service, minimal_observation):
        result = service.create(minimal_observation)
        assert result.observation_id is not None
        assert len(result.observation_id) > 0

    def test_create_with_quantity(
        self, service, patient, loinc_code, now_utc, valid_quantity
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            value_quantity=valid_quantity,
        )
        result = service.create(obs)
        assert result.value_quantity.value == Decimal("72")

    def test_create_with_issued_timestamp(
        self, service, patient, loinc_code, now_utc
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=now_utc,
        )
        result = service.create(obs)
        assert result.issued == now_utc

    def test_create_preserves_patient_reference(
        self, service, minimal_observation
    ):
        result = service.create(minimal_observation)
        assert result.patient.patient_id == "patient-001"

    def test_create_preserves_loinc_code(self, service, minimal_observation):
        result = service.create(minimal_observation)
        coding = result.code.codings[0]
        assert coding.system == LOINC_SYSTEM
        assert coding.code == "8867-4"

    def test_create_with_multiple_codings_including_loinc(
        self, service, patient, now_utc
    ):
        """LOINC among several codings must be accepted."""
        code = Code(
            codings=[
                Coding(system="http://snomed.info/sct", code="364075005"),
                Coding(system=LOINC_SYSTEM, code="8867-4", display="Heart rate"),
            ]
        )
        obs = Observation(patient=patient, code=code, effective_datetime=now_utc)
        result = service.create(obs)
        assert result is not None

    def test_create_with_status_final(self, service, minimal_observation):
        minimal_observation.status = "final"
        result = service.create(minimal_observation)
        assert result.status == "final"

    def test_create_with_status_preliminary(
        self, service, patient, loinc_code, now_utc
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            status="preliminary",
        )
        result = service.create(obs)
        assert result.status == "preliminary"


