class TestPatientValidation:

    def test_observation_without_patient_raises_missing_patient_error(
        self, service, loinc_code, now_utc
    ):
        obs = Observation(patient=None, code=loinc_code, effective_datetime=now_utc)
        with pytest.raises(MissingPatientError):
