    ):
        obs = Observation(
            patient=Patient(patient_id=""),
            code=loinc_code,
            effective_datetime=now_utc,
        )
        with pytest.raises(MissingPatientError):
            service.create(obs)

    def test_error_message_mentions_patient(
        self, service, loinc_code, now_utc
    ):
        obs = Observation(patient=None, code=loinc_code, effective_datetime=now_utc)
        with pytest.raises(MissingPatientError, match="patient"):
            service.create(obs)

    def test_missing_patient_is_validation_error_subclass(
        self, service, loinc_code, now_utc
    ):
        obs = Observation(patient=None, code=loinc_code, effective_datetime=now_utc)
        with pytest.raises(ValidationError):
            service.create(obs)


