    def test_non_loinc_coding_alone_raises_error(
        self, service, patient, now_utc
    ):
        code = Code(
            codings=[Coding(system="http://snomed.info/sct", code="364075005")]
        )
        obs = Observation(patient=patient, code=code, effective_datetime=now_utc)
        with pytest.raises(MissingCodeError):
            service.create(obs)

    def test_loinc_coding_with_empty_code_raises_error(
        self, service, patient, now_utc
    ):
        """A LOINC system entry with no code value must be rejected."""
        code = Code(codings=[Coding(system=LOINC_SYSTEM, code="")])
        obs = Observation(patient=patient, code=code, effective_datetime=now_utc)
        with pytest.raises(MissingCodeError):
