class TestTimestampBoundaries:

    # --- effective_datetime boundaries ---

    def test_effective_datetime_at_minimum_boundary_is_accepted(
        self, service, patient, loinc_code
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=DATETIME_MIN,
        )
        result = service.create(obs)
        assert result.effective_datetime == DATETIME_MIN

    def test_effective_datetime_at_maximum_boundary_is_accepted(
        self, service, patient, loinc_code
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=DATETIME_MAX,
        )
        result = service.create(obs)
        assert result.effective_datetime == DATETIME_MAX

    def test_effective_datetime_one_second_before_minimum_raises_error(
        self, service, patient, loinc_code
    ):
        just_before_min = DATETIME_MIN - timedelta(seconds=1)
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=just_before_min,
        )
        with pytest.raises(InvalidTimestampError):
            service.create(obs)

    def test_effective_datetime_one_second_after_maximum_raises_error(
        self, service, patient, loinc_code
    ):
        just_after_max = DATETIME_MAX + timedelta(seconds=1)
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=just_after_max,
        )
        with pytest.raises(InvalidTimestampError):
            service.create(obs)

    def test_effective_datetime_naive_raises_error(
        self, service, patient, loinc_code
    ):
        naive_dt = datetime(2024, 6, 15, 12, 0, 0)  # no tzinfo
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=naive_dt,
        )
        with pytest.raises(InvalidTimestampError, match="(?i)timezone"):
            service.create(obs)

    def test_effective_datetime_wrong_type_raises_error(
        self, service, patient, loinc_code
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime="2024-06-15T12:00:00Z",  # string instead of datetime
        )
        with pytest.raises(InvalidTimestampError):
            service.create(obs)

    def test_effective_datetime_none_is_allowed(
        self, service, patient, loinc_code
    ):
        """effective_datetime is optional; None must pass validation."""
        obs = Observation(patient=patient, code=loinc_code, effective_datetime=None)
        result = service.create(obs)
        assert result is not None

    # --- issued boundaries ---

    def test_issued_at_minimum_boundary_is_accepted(
        self, service, patient, loinc_code, now_utc
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=DATETIME_MIN,
        )
        result = service.create(obs)
        assert result.issued == DATETIME_MIN

    def test_issued_at_maximum_boundary_is_accepted(
        self, service, patient, loinc_code, now_utc
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=DATETIME_MAX,
        )
        result = service.create(obs)
        assert result.issued == DATETIME_MAX

    def test_issued_before_minimum_raises_error(
        self, service, patient, loinc_code, now_utc
    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=DATETIME_MIN - timedelta(seconds=1),
        )
        with pytest.raises(InvalidTimestampError):
            service.create(obs)

    def test_issued_after_maximum_raises_error(
