    ):
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=DATETIME_MAX + timedelta(seconds=1),
        )
        with pytest.raises(InvalidTimestampError):
            service.create(obs)

    def test_issued_naive_raises_error(
        self, service, patient, loinc_code, now_utc
    ):
        naive_issued = datetime(2024, 6, 15, 12, 0, 0)
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            issued=naive_issued,
