        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            value_quantity=Quantity(value=72.0, unit="beats/min"),  # type: ignore[arg-type]
        )
        with pytest.raises(InvalidQuantityError):
            service.create(obs)

    def test_quantity_value_as_int_raises_error(
        self, service, patient, loinc_code, now_utc
    ):
        """int is not acceptable; only Decimal."""
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            value_quantity=Quantity(value=72, unit="beats/min"),  # type: ignore[arg-type]
        )
        with pytest.raises(InvalidQuantityError):
            service.create(obs)

    def test_quantity_none_is_allowed(
        self, service, patient, loinc_code, now_utc
    ):
        """value_quantity is optional."""
        obs = Observation(
            patient=patient,
            code=loinc_code,
            effective_datetime=now_utc,
            value_quantity=None,
        )
        result = service.create(obs)
        assert result is not None

    @pytest.mark.parametrize("value,unit", [
        (Decimal("98.6"),    "degF"),
        (Decimal("120"),     "mm[Hg]"),
        (Decimal("5.5"),     "mmol/L"),
        (Decimal("0.001"),   "g"),
        (Decimal("999999"),  "IU/L"),
